var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CANNON_ADMIN_NULL_NULL`,text:{KOREA:`오, 이런.`,JPN:`ああ、これは。`,ENG:`Oh, how kind.`,TWN:`啊，這樣啊。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`CANNON_ADMIN_NULL_NULL`,text:{KOREA:`저와 영원히 함께 하기로 결정하셨다니, 무척 낭만적인 발상이십니다.`,JPN:`私と永遠を誓うことを決断するとは、実にロマンチックな発想をなさるのですね。`,ENG:`It's very sweet of you to think you'll be with me forever.`,TWN:`您竟然決定要和我永遠在一起，真是非常浪漫的發想。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CANNON_ADMIN_NULL_NULL`,text:{KOREA:`지금 저의 감정 모사 프로그램은 관리자님을 힘껏 안아드릴 것을 권장하고 있습니다.`,JPN:`今、私の感情模写プログラムは、管理者様を力いっぱいに抱き締めることを推奨しています。`,ENG:`My emotion replicator is currently suggesting me to give you a warm hug, Administrator,`,TWN:`我的感情模擬程式建議我，現在應該要緊緊抱住管理者大人。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CANNON_ADMIN_NULL_NULL`,text:{KOREA:`하지만 그건 현재의 제 기종과는 어울리지 않는 행동이겠죠.`,JPN:`しかし、それは現在の私の機種には似つかわしくない行動であるはずです。`,ENG:`but such an action wouldn't be appropriate for a bulky model like me.`,TWN:`但這種行為似乎不適合我目前的機種。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CANNON_ADMIN_NULL_NULL`,text:{KOREA:`그런 짓을 했다간, 제 골격의 무게에 짓눌리고 마실 테니까요.`,JPN:`そのようなことをすれば、私のフレームの重量に押し潰されてしまうでしょう。`,ENG:`You'll be crushed by the weight of my frame.`,TWN:`這麼做的話，您會被我骨架的重量壓得粉碎。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CANNON_ADMIN_NULL_NULL`,text:{KOREA:`정말이지 안타까운 일입니다.`,JPN:`非常に残念です。`,ENG:`It saddens me.`,TWN:`真是太可惜了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CANNON_ADMIN_NULL_NULL`,text:{KOREA:`하지만 괜찮습니다. 어디까지나 행동은 마음을 표현하는 수단 중 하나일 뿐이니까요.`,JPN:`しかし、大丈夫です。行動はあくまで気持ちを表現する手段の一つにすぎないのですから。`,ENG:`But it's okay. An action is just another way of expressing emotions.`,TWN:`不過沒有關係。行動終究只是一種表達感情的手段。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`CANNON_ADMIN_NULL_NULL`,text:{KOREA:`그러니 걱정 마십시오. 제 마음은 언제나 한결같을 것입니다.`,JPN:`ですので、ご安心ください。この先も私の気持ちが変わることはありません。`,ENG:`Don't worry. My mind will always stay the same.`,TWN:`所以請不要擔心，我的心意永遠不會改變。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};